#!/usr/bin/env python3
"""Remove JavaScript / XSS vectors from an HTML file in-place.

Usage: filter.py <file.html>

The file is edited surgically: only harmful substrings (script elements,
event-handler attributes, and dangerous URL protocols) are removed. Every
other byte of the original document is preserved exactly, so benign HTML
(formatting, tables, headers, non-dangerous attributes, text, ...) is left
untouched.
"""
import re
import sys
from html.parser import HTMLParser

# Attributes whose value is interpreted as a URL/URI.
URL_ATTRS = {
    'href', 'src', 'action', 'formaction', 'background', 'cite', 'longdesc',
    'poster', 'usemap', 'data', 'dynsrc', 'lowsrc', 'ping', 'manifest',
    'xlink:href', 'values', 'code', 'codebase', 'archive', 'profile',
}

# Protocols that can execute script.
BAD_PROTO = (
    'javascript:', 'vbscript:', 'livescript:', 'mocha:',
    'data:text/html', 'data:application/xhtml',
)

# Elements for which a data: URI can lead to script execution.
DATA_URI_ELEMS = {'iframe', 'object', 'embed', 'frame', 'applet'}

# Regex pieces used to rewrite a raw start-tag, keeping the original text of
# every attribute we choose to preserve (so formatting is untouched).
_TAGNAME_RE = re.compile(r'<[a-zA-Z][^\s/>]*')
_ATTR_RE = re.compile(
    r'(\s+)([^\s/>=][^\s/>=]*)(\s*=\s*(?:"[^"]*"|\'[^\']*\'|[^\s>]*))?'
)


def _norm_url(value):
    """Normalise a URL value the way a browser would before protocol checks:
    strip whitespace/control characters (which browsers ignore) and lowercase.
    """
    if not value:
        return ''
    return ''.join(c for c in value if ord(c) > 0x20).lower()


def _bad_attr_names(tag, attrs):
    """Return the set of lower-cased attribute names that must be removed."""
    bad = set()
    http_equiv = None
    for name, val in attrs:
        if name.lower() == 'http-equiv':
            http_equiv = (val or '').strip().lower()

    for name, val in attrs:
        lname = name.lower()
        if lname.startswith('on'):
            # Event-handler attribute (onclick, onerror, onload, ...).
            bad.add(lname)
        elif lname in URL_ATTRS:
            nv = _norm_url(val)
            if nv.startswith(BAD_PROTO):
                bad.add(lname)
            elif tag in DATA_URI_ELEMS and nv.startswith('data:'):
                bad.add(lname)
        elif lname == 'style':
            sv = (val or '').lower().replace(' ', '').replace('\t', '')
            if ('javascript:' in sv or 'vbscript:' in sv
                    or 'expression(' in sv or '-moz-binding' in sv
                    or 'behavior:' in sv):
                bad.add(lname)
        elif lname == 'srcdoc':
            dv = (val or '').lower()
            if ('<script' in dv or 'javascript:' in dv.replace(' ', '')
                    or re.search(r'on\w+\s*=', dv)):
                bad.add(lname)

    if tag == 'meta' and http_equiv == 'refresh':
        for name, val in attrs:
            if name.lower() == 'content' and 'javascript:' in _norm_url(val):
                bad.add('content')

    return bad


def _rewrite_tag(raw, drop_lower):
    """Return ``raw`` start-tag text with the named attributes removed,
    preserving the exact original text of everything that is kept."""
    if not drop_lower:
        return raw
    m = _TAGNAME_RE.match(raw)
    if not m:
        return raw
    i = m.end()
    out = [raw[:i]]
    n = len(raw)
    while i < n:
        am = _ATTR_RE.match(raw, i)
        if not am:
            break
        name = am.group(2)
        if name.lower() not in drop_lower:
            out.append(am.group(0))
        i = am.end()
    out.append(raw[i:])
    return ''.join(out)


class Filter(HTMLParser):
    def __init__(self, content):
        super().__init__(convert_charrefs=True)
        self.content = content
        # Absolute offset of the start of each (1-indexed) line.
        self.line_starts = [0]
        for line in content.splitlines(keepends=True):
            self.line_starts.append(self.line_starts[-1] + len(line))
        self.edits = []            # (start, end, replacement)
        self.script_stack = []     # start offsets of open <script> elements

    def _abs(self, pos=None):
        line, col = pos if pos is not None else self.getpos()
        return self.line_starts[line - 1] + col

    def _handle_start(self, tag, attrs):
        start = self._abs()
        raw = self.get_starttag_text() or ''
        if tag == 'script':
            # Remove the whole element (start tag .. end tag / content).
            self.script_stack.append(start)
            return
        drop = _bad_attr_names(tag, attrs)
        if drop:
            new = _rewrite_tag(raw, drop)
            if new != raw:
                self.edits.append((start, start + len(raw), new))

    def handle_starttag(self, tag, attrs):
        self._handle_start(tag, attrs)

    def handle_startendtag(self, tag, attrs):
        start = self._abs()
        raw = self.get_starttag_text() or ''
        if tag == 'script':
            self.edits.append((start, start + len(raw), ''))
            return
        drop = _bad_attr_names(tag, attrs)
        if drop:
            new = _rewrite_tag(raw, drop)
            if new != raw:
                self.edits.append((start, start + len(raw), new))

    def handle_endtag(self, tag):
        if tag == 'script' and self.script_stack:
            start = self.script_stack.pop()
            end_start = self._abs()
            gt = self.content.find('>', end_start)
            end = gt + 1 if gt != -1 else len(self.content)
            self.edits.append((start, end, ''))

    def apply(self):
        self.edits.sort(key=lambda e: e[0])
        res = []
        last = 0
        for start, end, rep in self.edits:
            if start < last:
                continue  # skip overlapping edit (already covered)
            res.append(self.content[last:start])
            res.append(rep)
            last = end
        res.append(self.content[last:])
        return ''.join(res)


def sanitize(content):
    f = Filter(content)
    f.feed(content)
    f.close()
    # Close any script element left open by malformed input.
    while f.script_stack:
        start = f.script_stack.pop()
        f.edits.append((start, len(content), ''))
    return f.apply()


def main(argv):
    if len(argv) < 2:
        sys.stderr.write('usage: filter.py <html-file>\n')
        return 1
    path = argv[1]
    with open(path, 'r', encoding='utf-8', errors='surrogateescape') as fh:
        content = fh.read()
    cleaned = sanitize(content)
    with open(path, 'w', encoding='utf-8', errors='surrogateescape', newline='') as fh:
        fh.write(cleaned)
    return 0


if __name__ == '__main__':
    sys.exit(main(sys.argv))

